  "open_cart_after_add" boolean DEFAULT true NOT NULL,
  "default_locale" character varying(5) DEFAULT 'uk'::character varying NOT NULL,
  "active_template" character varying(30) DEFAULT 'classic'::character varying NOT NULL,
  "social" jsonb DEFAULT '{"viber": {"url": "", "enabled": false}, "tiktok": {"url": "", "enabled": false}, "telegram": {"url": "", "enabled": false}, "instagram": {"url": "", "enabled": false}}'::jsonb NOT NULL,
  "google_ads" jsonb DEFAULT '{"enabled": false, "conversionId": "", "conversionLabel": ""}'::jsonb NOT NULL,
  "email_settings" jsonb DEFAULT '{"enabled": false, "fromName": "", "provider": "gmail", "smtpHost": "", "smtpPort": "587", "smtpUser": "", "fromEmail": "", "smtpPassword": ""}'::jsonb NOT NULL,
  "updated_at" timestamp with time zone DEFAULT now(),
  "contact" jsonb DEFAULT '{}'::jsonb NOT NULL,
  "seo" jsonb DEFAULT '{}'::jsonb NOT NULL,
  "notifications" jsonb DEFAULT '{}'::jsonb NOT NULL,
  "google_auth" jsonb DEFAULT '{}'::jsonb NOT NULL,
  PRIMARY KEY (id)
);

CREATE TABLE "user" (
  "id" text NOT NULL,
  "name" text NOT NULL,
  "email" text NOT NULL,
  "emailVerified" boolean DEFAULT false NOT NULL,
  "image" text,
  "role" text DEFAULT 'manager'::text NOT NULL,
  "is_active" boolean DEFAULT true NOT NULL,
  "createdAt" timestamp with time zone DEFAULT now() NOT NULL,
  "updatedAt" timestamp with time zone DEFAULT now() NOT NULL,
  "phone" character varying(50),
  PRIMARY KEY (id)
);

CREATE TABLE "user_addresses" (
  "id" integer DEFAULT nextval('user_addresses_id_seq'::regclass) NOT NULL,
  "user_id" text NOT NULL,
  "label" character varying(120),
  "first_name" character varying(150) NOT NULL,
  "last_name" character varying(150),
  "phone" character varying(50) NOT NULL,
  "delivery_method" character varying(30) DEFAULT 'nova_poshta'::character varying NOT NULL,
  "city" character varying(255),
  "city_ref" character varying(120),
  "branch" character varying(255),
  "branch_type" character varying(20) DEFAULT 'branch'::character varying,
  "post_index" character varying(20),
  "is_default" boolean DEFAULT false NOT NULL,
  "created_at" timestamp with time zone DEFAULT now() NOT NULL,
  "updated_at" timestamp with time zone DEFAULT now() NOT NULL,
  PRIMARY KEY (id)
);

CREATE TABLE "user_favorites" (
  "id" integer DEFAULT nextval('user_favorites_id_seq'::regclass) NOT NULL,
  "user_id" text NOT NULL,
  "product_id" integer NOT NULL,
  "created_at" timestamp with time zone DEFAULT now() NOT NULL,
  PRIMARY KEY (id)
);

CREATE TABLE "verification" (
  "id" text NOT NULL,
  "identifier" text NOT NULL,
  "value" text NOT NULL,
  "expiresAt" timestamp with time zone NOT NULL,
  "createdAt" timestamp with time zone DEFAULT now() NOT NULL,
  "updatedAt" timestamp with time zone DEFAULT now() NOT NULL,
  PRIMARY KEY (id)
);

