-- pages (5 rows)
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "excerpt_ru", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES ('1','Угода користувача','Пользовательское соглашение','terms','<p>Ця Угода користувача регулює використання інтернет-магазину. Користуючись сайтом, ви погоджуєтесь з умовами цієї Угоди.</p><h2>1. Загальні положення</h2><p>Адміністрація сайту надає користувачу доступ до перегляду та замовлення товарів.</p><h2>2. Замовлення</h2><p>Оформлюючи замовлення, користувач підтверджує достовірність наданих даних.</p><h2>3. Відповідальність</h2><p>Сторони несуть відповідальність згідно з чинним законодавством України.</p>','<p>Настоящее Пользовательское соглашение регулирует использование интернет-магазина. Используя сайт, вы соглашаетесь с условиями данного Соглашения.</p><h2>1. Общие положения</h2><p>Администрация сайта предоставляет пользователю доступ к просмотру и заказу товаров.</p><h2>2. Заказы</h2><p>Оформляя заказ, пользователь подтверждает достоверность предоставленных данных.</p><h2>3. Ответственность</h2><p>Стороны несут ответственность в соответствии с действующим законодательством Украины.</p>',NULL,NULL,NULL,'default','published','false',NULL,'1',NULL,NULL,'2026-07-12 14:06:18.541292+00','2026-07-12 14:06:18.541292+00','2026-07-12 14:06:18.541292+00');
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "excerpt_ru", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES ('2','Політика конфіденційності','Политика конфиденциальности','privacy','<p>Ми поважаємо вашу приватність та захищаємо персональні дані відповідно до законодавства України.</p><h2>1. Збір даних</h2><p>Ми збираємо лише ті дані, які необхідні для оформлення та доставки замовлення.</p><h2>2. Використання даних</h2><p>Персональні дані використовуються виключно для обробки замовлень та зв''язку з вами.</p><h2>3. Захист даних</h2><p>Ми вживаємо всіх необхідних заходів для захисту ваших персональних даних.</p>','<p>Мы уважаем вашу конфиденциальность и защищаем персональные данные в соответствии с законодательством Украины.</p><h2>1. Сбор данных</h2><p>Мы собираем только те данные, которые необходимы для оформления и доставки заказа.</p><h2>2. Использование данных</h2><p>Персональные данные используются исключительно для обработки заказов и связи с вами.</p><h2>3. Защита данных</h2><p>Мы принимаем все необходимые меры для защиты ваших персональных данных.</p>',NULL,NULL,NULL,'default','published','false',NULL,'2',NULL,NULL,'2026-07-12 14:06:18.541292+00','2026-07-12 14:06:18.541292+00','2026-07-12 14:06:18.541292+00');
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "excerpt_ru", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES ('3','Політика повернення','Политика возвратов','returns','<p>Ви можете повернути товар протягом 14 днів з моменту отримання згідно із Законом України «Про захист прав споживачів».</p><h2>1. Умови повернення</h2><p>Товар має бути у непошкодженому вигляді, зі збереженням товарного вигляду та упаковки.</p><h2>2. Як оформити повернення</h2><p>Зв''яжіться з нашою службою підтримки для оформлення заявки на повернення.</p><h2>3. Повернення коштів</h2><p>Кошти повертаються протягом 7 робочих днів після отримання товару.</p>','<p>Вы можете вернуть товар в течение 14 дней с момента получения согласно Закону Украины «О защите прав потребителей».</p><h2>1. Условия возврата</h2><p>Товар должен быть в неповреждённом виде, с сохранением товарного вида и упаковки.</p><h2>2. Как оформить возврат</h2><p>Свяжитесь с нашей службой поддержки для оформления заявки на возврат.</p><h2>3. Возврат средств</h2><p>Средства возвращаются в течение 7 рабочих дней после получения товара.</p>',NULL,NULL,NULL,'default','published','false',NULL,'3',NULL,NULL,'2026-07-12 14:06:18.541292+00','2026-07-12 14:06:18.541292+00','2026-07-12 14:06:18.541292+00');
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "excerpt_ru", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES ('5','Про PowerFox',NULL,'about','<h2>Ласкаво просимо до PowerFox!</h2><p>Ми спеціалізуємося на сучасних зарядних пристроях та аксесуарах для смартфонів, планшетів, ноутбуків та інших гаджетів. У нашому асортименті представлені зарядні пристрої GaN брендів: Toocki, Essager, Asometech та інших, кабелі Type-C - Type-C, автомобільні зарядні пристрої 6/8/10 ампер.</p><p>Ми ретельно підбираємо товари, стежимо за актуальністю асортименту та прагнемо пропонувати оптимальне співвідношення ціни та якості. Перед відправкою перевіряємо комплектацію та стан товару, щоб ви отримали замовлення без неприємних сюрпризів.</p><p>Для нас важливі чесний сервіс, швидка обробка замовлень і допомога у виборі. Якщо у вас виникли питання щодо сумісності або характеристик товару — ми завжди готові допомогти.</p><p>Дякуємо, що обираєте PowerFox!</p>',NULL,'Хто ми та чому нам довіряють',NULL,NULL,'default','published','true','Про нас','1','Про PowerFox — зарядні пристрої та аксесуари',NULL,'2026-07-12 15:57:39.680688+00','2026-07-12 15:57:39.680688+00','2026-07-12 15:57:39.680688+00');
INSERT INTO "pages" ("id", "title", "title_ru", "slug", "content", "content_ru", "excerpt", "excerpt_ru", "cover_image", "template", "status", "show_in_menu", "menu_title", "sort_order", "meta_title", "meta_description", "published_at", "created_at", "updated_at") VALUES ('4','Доставка та оплата','Доставка и оплата','delivery','<p>Ми доставляємо замовлення по всій Україні зручними для вас способами.</p><h2>1. Способи доставки</h2><ul><li>Нова Пошта — 1-3 робочі дні</li><li>Укрпошта — 3-7 робочих днів</li><li>Кур''єрська доставка по місту</li></ul><h2>2. Способи оплати</h2><ul><li>Накладений платіж при отриманні</li><li>Оплата картою онлайн</li><li>Безготівковий розрахунок</li></ul><h2>3. Вартість доставки</h2><p>Вартість доставки розраховується за тарифами перевізника.</p>','<p>Мы доставляем заказы по всей Украине удобными для вас способами.</p><h2>1. Способы доставки</h2><ul><li>Нова Пошта — 1-3 рабочих дня</li><li>Укрпошта — 3-7 рабочих дней</li><li>Курьерская доставка по городу</li></ul><h2>2. Способы оплаты</h2><ul><li>Наложенный платёж при получении</li><li>Оплата картой онлайн</li><li>Безналичный расчёт</li></ul><h2>3. Стоимость доставки</h2><p>Стоимость доставки рассчитывается по тарифам перевозчика.</p>',NULL,NULL,NULL,'default','published','false',NULL,'4',NULL,NULL,'2026-07-12 14:06:18.541292+00','2026-07-12 14:06:18.541292+00','2026-07-12 18:43:29.685724+00');

