INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('68','Зарядний пристрій для автомобільного акумулятора 12V 10A для літій-залізофосфатних акумуляторів Liітій-залізофосфатних а','Зарядное устройство для автомобильного аккумулятора 12V 10A для литий-железофосфатных аккумуляторов Litiй-железофосфатных а','<span style="display:block;font-size:14px;margin:1em 0">Інтелектуальний зарядний пристрій для акумуляторів 12V 10A Pulse Repair Charger LCD</span>
<p><strong>Автоматичний зарядний пристрій 12В 10А з функцією відновлення (Pulse Repair)</strong> призначений для заряджання та обслуговування свинцево-кислотних, AGM, GEL та LiFePO4 акумуляторів. Оснащений цифровим LCD-дисплеєм, який відображає струм заряджання, напругу, рівень заряду та поточний режим роботи.</p>
<p>Завдяки вбудованому інтелектуальному контролеру пристрій автоматично підбирає оптимальні параметри заряджання, захищаючи акумулятор від перезаряду, перегріву та короткого замикання.</p>
<span style="display:block;font-size:14px;margin:1em 0">Переваги:</span>
<p>✅ Інтелектуальне автоматичне заряджання<br>
✅ Функція відновлення акумулятора Pulse Repair<br>
✅ LCD-дисплей з відображенням параметрів зарядки<br>
✅ Захист від короткого замикання<br>
✅ Захист від перегріву<br>
✅ Захист від переполюсування<br>
✅ Підтримка AGM, GEL, SLA та LiFePO4 акумуляторів<br>
✅ Режим "Зима / Літо"<br>
✅ Автоматичне відключення після завершення заряджання</p>
<span style="display:block;font-size:14px;margin:1em 0">Технічні характеристики:</span>
<ul>
<li>Тип пристрою: автоматичний зарядний пристрій</li>
<li>Вхідна напруга: 220-240 В, 50/60 Гц</li>
<li>Вихідна напруга: 12 В</li>
<li>Максимальний струм зарядки: 10 А</li>
<li>Тип дисплея: LCD</li>
<li>Підтримувані акумулятори: AGM, GEL, SLA, WET, LiFePO4</li>
<li>Ємність акумуляторів: 6-200 А·год</li>
<li>Функція відновлення: Pulse Repair</li>
<li>Матеріал корпусу: ABS-пластик</li>
<li>Колір: червоний</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Комплектація:</span>
<ul>
<li>Зарядний пристрій 12V 10A</li>
<li>Кабель живлення 220В</li>
<li>Кабелі з клемами "крокодил"</li>
<li>Інструкція</li>
<li>Упаковка</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Застосування:</span>
<p>Підходить для заряджання акумуляторів легкових автомобілів, мотоциклів, скутерів, квадроциклів, човнів, газонокосарок та іншої техніки з акумуляторами 12 В.</p>
<p><strong>Надійне рішення для заряджання та відновлення акумулятора в домашніх умовах та гаражі.</strong></p>','<span style="display:block;font-size:14px;margin:1em 0">Интеллектуальное зарядное устройство для аккумуляторов 12V 10A Pulse Repair Charger LCD</span>
<p><strong>Автоматическое зарядное устройство 12В 10А с функцией восстановления (Pulse Repair)</strong> предназначен для зарядки и обслуживания свинцово-кислотных, AGM, GEL и LiFePO4 аккумуляторов. Оснащен цифровым LCD дисплеем, который отображает ток зарядки, напряжение, уровень заряда и текущий режим работы.</p>
<p>Благодаря встроенному интеллектуальному контроллеру устройство автоматически подбирает оптимальные параметры зарядки, защищая аккумулятор от перезаряда, перегрева и короткого замыкания.</p>
<span style="display:block;font-size:14px;margin:1em 0">Преимущества:</span>
<p>✅ Интеллектуальная автоматическая зарядка<br>
✅ Функция восстановления аккумулятора Pulse Repair<br>
✅ LCD-дисплей с отображением настроек зарядки<br>
✅ Защита от короткого замыкания<br>
✅ Защита от перегрева<br>
✅ Защита от переполюсовки<br>
✅ Поддержка AGM, GEL, SLA и LiFePO4 аккумуляторов<br>
✅ Режим "Зима / Лето"<br>
✅ Автоматическое отключение по завершении зарядки</p>
<span style="display:block;font-size:14px;margin:1em 0">Технические характеристики:</span>
<ul>
<li>Тип устройства: автоматическое зарядное устройство</li>
<li>Входное напряжение: 220-240 В, 50/60 Гц</li>
<li>Выходное напряжение: 12 В</li>
<li>Максимальный ток зарядки: 10 А</li>
<li>Тип дисплея: LCD</li>
<li>Поддерживаемые аккумуляторы: AGM, GEL, SLA, WET, LiFePO4</li>
<li>Емкость аккумуляторов: 6-200 Ач</li>
<li>Функция восстановления: Pulse Repair</li>
<li>Материал корпуса: ABS пластик</li>
<li>Цвет: красный</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Комплектация:</span>
<ul>
<li>Зарядное устройство 12V 10A</li>
<li>Кабель питания 220В</li>
<li>Кабели с клеммами "крокодил"</li>
<li>Инструкция</li>
<li>Упаковка</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Применение:</span>
<p>Подходит для зарядки аккумуляторов легковых автомобилей, мотоциклов, скутеров, квадроциклов, лодок, газонокосилок и другой техники с аккумуляторами 12 В.</p>
