<li>Фирменная упаковка.</li>
</ul>',NULL,'retail','P1011160A113-01',NULL,'699.00','false','UAH',NULL,NULL,'100','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7544603780_w700_h500_mzu-baseus-palm.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544603780_w700_h500_mzu-baseus-palm-LytG2Y12DmBjO9I5ECXuqz5yLcFp48.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7534465299_w700_h500_mzu-baseus-palm-SVhmwToarWspdkmHtxTqgMARgKnhzn.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7534465293_w700_h500_mzu-baseus-palm-SgTYDV9szVUsi2XlXctb8qeSq299BR.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7534465289_w700_h500_mzu-baseus-palm-FvUK6dOHK6JcESi2nrNoRyWpgH9ssi.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7534465290_w700_h500_mzu-baseus-palm-D76VSVFYsf6K9M8QK1LhO9fnhcjlU1.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7534465292_w700_h500_mzu-baseus-palm-4A5R3P1GKgaeTq3mTRlSROapSgURsm.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7534465297_w700_h500_mzu-baseus-palm-m5HtKn52RBfh0XJfWYHgAi3RijoAIT.png"]','[]','[]','true','true','false','68','0','0',NULL,NULL,NULL,NULL,'2026-07-12 15:03:43.500666+00','2026-07-12 15:03:43.500666+00',NULL,'0');
