INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('49','Мережевий зарядний пристрій ESSAGER 65W GaN з висувним кабелем Type C','Сетевое зарядное устройство ESSAGER 65W GaN с выдвижным кабелем Type C','Мережевий зарядний пристрій ESSAGER 65W GaN з висувним кабелем Type C (G652CE) призначений для швидкого та стабільного живлення сучасних смартфонів, планшетів та іншої мобільної електроніки. Завдяки використанню технології GaN зарядка забезпечує високу потужність при компактних розмірах, що робить її зручним рішенням для дому, офісу та подорожей. Універсальний діапазон вхідної напруги та підтримка популярних стандартів швидкого заряджання дозволяють використовувати пристрій з технікою різних брендів. Особливості зарядного пристрою: Технологія GaN — підвищена енергоефективність, знижене нагрівання та компактний корпус. Максимальна потужність 65W — підходить для смартфонів, планшетів та інших пристроїв із підтримкою Power Delivery. Два виходи Type-C — можливість одночасного заряджання двох пристроїв. Підтримка кількох протоколів — PD, QC, Samsung Adaptive Fast Charge, Huawei FCP, BC1.2. Формат для подорожей — легка та компактна конструкція з вилкою EU або US. Сертифікація якості — відповідність стандартам CE, CCC, FCC та RoHS. Технічні характеристики: Загальні параметри Тип: мережевий зарядний пристрій (Travel) Бренд: ESSAGER Модель: G652CE Матеріал корпусу: ABS + PC Колір: чорний Технологія GaN: так Екран: відсутній Інтелектуальне заряджання: ні Хімічні речовини підвищеного ризику: відсутні Живлення та потужність Максимальна вихідна потужність: 65W Вхідна напруга: 110–240V~50/60Hz, 1.5A Max Вихідний інтерфейс: Type-C Вихідні параметри (один порт) 5V ⎓ 3A 9V ⎓ 3A 12V ⎓ 3A 15V ⎓ 3A 20V ⎓ 3.25A Режими роботи портів Type-C кабель: до 65W Type-C порт: до 65W Одночасна робота: Type-C кабель + Type-C порт — 45W + 20W (65W Max) Підтримувані протоколи швидкого заряджання USB Power Delivery (PD) Qualcomm Quick Charge Samsung Adaptive Fast Charge Huawei FCP BC1.2 Сумісність Смартфони iPhone серій 6–16, включно з версіями Pro та Pro Max Планшети iPad Mini 2/3/4, iPad Air Інші пристрої з роз’ємом Type-C та підтримкою PD або QC','Сетевое зарядное устройство ESSAGER 65W GaN с выдвижным кабелем Type C (G652CE) предназначено для быстрого и стабильного питания современных смартфонов, планшетов и другой мобильной электроники. Благодаря использованию технологии GaN зарядка обеспечивает высокую мощность при компактных размерах, что делает ее удобным решением для дома, офиса и путешествий. Универсальный диапазон входного напряжения и поддержка популярных стандартов быстрой зарядки позволяют использовать устройство с техникой различных брендов. Особенности зарядного устройства: Технология GaN — повышенная энергоэффективность, пониженный нагрев и компактный корпус. Максимальная мощность 65W — подходит для смартфонов, планшетов и других устройств с поддержкой Power Delivery. Два выхода Type-C – возможность одновременной зарядки двух устройств. Поддержка нескольких протоколов — PD, QC, Samsung Adaptive Fast Charge, Huawei FCP, BC1.2. Формат для путешествий – легкая и компактная конструкция с вилкой EU или US. Сертификация качества – соответствие стандартам CE, CCC, FCC и RoHS. Технические характеристики: Общие параметры Тип: сетевое зарядное устройство (Travel) Бренд: ESSAGER Модель: G652CE Материал корпуса: ABS + PC Цвет: черный Технология GaN: да Экран: отсутствие Интеллектуальная зарядка: ни Химические вещества повышенного риска: отсутствуют Питание и мощность Максимальная выходная мощность: 65W Входное напряжение: 110–240V~50/60Hz, 1.5A Max Выходной интерфейс: Type-C Выходные настройки (один порт) 5V | 3A 9V | 3A 12V | 3A 15V | 3A 20V | 3.25A Режимы работы портов Type-C кабель: до 65W Type-C порт: до 65W Одновременная работа: Type-C кабель + Type-C порт - 45W + 20W (65W Max) Поддерживаемые протоколы быстрой зарядки USB Power Delivery (PD) Qualcomm Quick Charge Samsung Adaptive Fast Charge Huawei FCP BC1.2 Совместимость Смартфоны iPhone серий 6–16, включая версии Pro и Pro Max Планшеты iPad Mini 2/3/4, iPad Air Другие устройства с разъемом Type-C и поддержкой PD или QC',NULL,'retail','ECT65W-RZB01-Z',NULL,'699.00','false','UAH',NULL,NULL,'100','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7544699036_w700_h500_setevoe-zaryadnoe-ustrojstvo.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544699036_w700_h500_setevoe-zaryadnoe-ustrojstvo-s0S0AxLRcTWA1iJlPH0CPoeh9mcYsh.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7466303458_w700_h500_setevoe-zaryadnoe-ustrojstvo-tidpOezmbK5314OIKhKovESB8TdGtk.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7466303679_w700_h500_setevoe-zaryadnoe-ustrojstvo-TBWBFREBwSTdYZgFERhDRGhK7ZZgEE.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7466303754_w700_h500_setevoe-zaryadnoe-ustrojstvo-hGBIrshCjAb1KFJWf1YSUcAbaVGbUf.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7419438908_w700_h500_setevoe-zaryadnoe-ustrojstvo-aBWZ7XDsN7mDkGl1gVFzw5AgiZZhS0.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7419439279_w700_h500_setevoe-zaryadnoe-ustrojstvo-WQgN3iwlHVFyNVinSBKFzzCp0yX34e.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7419442600_w700_h500_setevoe-zaryadnoe-ustrojstvo-1PokE9mXy12roeDJVtF1FRjqV7lvGA.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7419442857_w700_h500_setevoe-zaryadnoe-ustrojstvo-sKsMEjzZcG9YNEr4xkiE9qYob3bEwt.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7419443134_w700_h500_setevoe-zaryadnoe-ustrojstvo-QAQ7psgDDa6xf7l1vaV0YPQrdU2mEo.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7419443500_w700_h500_setevoe-zaryadnoe-ustrojstvo-KDpOO7I8bKu5IdMnriiF2QSJjY5wIM.jpg"]','[]','[]','true','true','false','8','0','0',NULL,NULL,NULL,NULL,'2026-07-12 15:03:43.500666+00','2026-07-12 15:03:43.500666+00',NULL,'0');
