<li>Материал корпуса: <strong>ABS пластик + силикон</strong></li>
<li>Питание: <strong>USB Type-C (5 В / 2 А)</strong></li>
<li>Размеры: <strong>165 × 270 × 366 мм</strong></li>
<li>Цвет: <strong>белый</strong>.</li>
</ul>
<p> </p>
<p> </p>',NULL,'retail','DLMM22000202',NULL,'1899.00','false','UAH',NULL,NULL,'100','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7545966970_w700_h500_nastolnaya-lampa-proove.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7545966970_w700_h500_nastolnaya-lampa-proove-11SBTA8eKb7IwiNgIBN5US6RNNPtl3.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530294620_w700_h500_nastolnaya-lampa-proove-5Up62pbtI0p0sk4Sq9afFHKG44LMc3.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530296872_w700_h500_nastolnaya-lampa-proove-D0ICiggTyb3pYUOpo5BKCtH5qH6Iu4.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530306320_w700_h500_nastolnaya-lampa-proove-9iFHb3vNUtMMpqaiWRZ8n6U4sIpZe7.png"]','[]','[]','true','true','false','50','0','0',NULL,NULL,NULL,NULL,'2026-07-12 15:03:43.500666+00','2026-07-12 15:03:43.500666+00',NULL,'0');
