INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('94','Універсальний дорожній адаптер Proove Trip 20W 9 Black, мережевий перехідник із USB-A та USB-C, швидка зарядка PD 20W','Универсальный дорожный адаптер Proove Trip 20W 9 Black, сетевой переходник с USB-A и USB-C, быстрая зарядка PD 20W','<p><strong>Proove Trip 20W</strong> — це універсальний дорожній адаптер, який дозволяє безпечно користуватися електронікою та заряджати гаджети практично в будь-якій країні світу. Завдяки підтримці стандартів розеток <strong>EU, US, UK та AU</strong> він стане незамінним аксесуаром для подорожей, відряджень і відпочинку. Пристрій оснащений одним портом <strong>USB Type-C</strong>, двома <strong>USB-A</strong> та універсальною AC-розеткою, що дозволяє одночасно заряджати кілька пристроїв.</p>
<p>Швидка зарядка через <strong>USB Type-C</strong> потужністю до <strong>20 Вт</strong> і <strong>USB-A</strong> до <strong>18 Вт</strong> забезпечує ефективне заряджання смартфонів, планшетів, навушників та інших гаджетів. Максимальна потужність AC-виходу становить <strong>2500 Вт</strong>, що дозволяє підключати широкий спектр побутової техніки, сумісної з місцевою електромережею.</p>
<p>Корпус адаптера виготовлений із <strong>вогнестійкого пластику</strong>, а вбудовані системи захисту від перевантаження, короткого замикання та перепадів напруги забезпечують безпечну експлуатацію. Компактний розмір робить адаптер зручним для перевезення в сумці або рюкзаку.</p>
<span style="display:block;font-size:14px;margin:1em 0"><strong>Переваги:</strong></span>
<ul>
<li>Підходить для більшості країн світу (EU / US / UK / AU).</li>
<li>Швидка зарядка USB Type-C до <strong>20 Вт</strong>.</li>
<li>Два порти USB-A із підтримкою зарядки до <strong>18 Вт</strong>.</li>
<li>Одночасне заряджання кількох пристроїв.</li>
<li>Універсальна AC-розетка.</li>
<li>Максимальне навантаження AC — <strong>2500 Вт</strong>.</li>
<li>Вбудований захист від перевантаження, короткого замикання та перепадів напруги.</li>
<li>Компактний корпус із вогнестійкого пластику.</li>
<li>Ідеальний для подорожей та відряджень.</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0"><strong>Характеристики:</strong></span>
<ul>
<li><strong>Бренд:</strong> Proove</li>
<li><strong>Модель:</strong> Trip 20W 9</li>
<li><strong>Тип:</strong> універсальний дорожній адаптер</li>
<li><strong>Колір:</strong> Black (чорний)</li>
<li><strong>Вхід:</strong> AC 100–250 В, 50/60 Гц</li>
<li><strong>Номінальний струм:</strong> 10 А</li>
<li><strong>AC-вихід:</strong> до 2500 Вт</li>
<li><strong>USB Type-C:</strong> до 20 Вт</li>
<li><strong>USB-A:</strong> до 18 Вт</li>
<li><strong>Порти:</strong> 1×USB Type-C, 2×USB-A, 1×AC</li>
<li><strong>Матеріал корпусу:</strong> вогнестійкий пластик</li>
<li><strong>Країна виробництва:</strong> Китай</li>
</ul>','<p><strong>Proove Trip 20W 9</strong> — это универсальный дорожный адаптер, который позволяет подключать и быстро заряжать устройства практически в любой стране мира. Благодаря поддержке популярных стандартов розеток <strong>EU, US, UK и AU</strong> адаптер станет незаменимым помощником в путешествиях, командировках и отпуске.</p>
<p>Модель оснащена <strong>универсальной AC-розеткой</strong>, одним портом <strong>USB Type-C</strong> с поддержкой быстрой зарядки <strong>Power Delivery до 20 Вт</strong> и двумя портами <strong>USB-A</strong> с поддержкой <strong>Quick Charge до 18 Вт</strong>. Это позволяет одновременно заряжать смартфоны, планшеты, наушники, смарт-часы и другие электронные устройства.</p>
<p>Корпус изготовлен из прочного огнестойкого пластика, устойчивого к высоким температурам. Встроенные системы защиты предотвращают перегрев, перегрузку, короткое замыкание и скачки напряжения, обеспечивая безопасную работу подключенной техники.</p>
<p>Компактные размеры и небольшой вес делают адаптер удобным для переноски, а современный дизайн отлично дополняет любой комплект дорожных аксессуаров.</p>
<span style="display:block;font-size:14px;margin:1em 0"><strong>Преимущества:</strong></span>
<ul>
<li>Подходит для использования более чем в 200 странах мира.</li>
<li>Поддержка стандартов вилок <strong>EU / US / UK / AU</strong>.</li>
<li>Быстрая зарядка <strong>USB Type-C Power Delivery до 20 Вт</strong>.</li>
<li>Два порта <strong>USB-A Quick Charge до 18 Вт</strong>.</li>
<li>Возможность одновременной зарядки нескольких устройств.</li>
<li>Максимальная мощность AC-розетки — <strong>2500 Вт</strong>.</li>
<li>Защита от перегрева, перегрузки, короткого замыкания и перенапряжения.</li>
<li>Прочный корпус из огнестойкого пластика.</li>
<li>Компактный размер — идеальный вариант для путешествий.</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0"><strong>Характеристики:</strong></span>
<ul>
<li><strong>Бренд:</strong> Proove</li>
<li><strong>Модель:</strong> Trip 20W 9</li>
<li><strong>Тип:</strong> универсальный дорожный адаптер</li>
<li><strong>Цвет:</strong> Black (черный)</li>
<li><strong>Входное напряжение:</strong> AC 100–250 В, 50/60 Гц</li>
<li><strong>Максимальный ток:</strong> 10 А</li>
<li><strong>Максимальная мощность AC:</strong> 2500 Вт</li>
<li><strong>USB Type-C:</strong> до 20 Вт (PD)</li>
<li><strong>USB-A:</strong> до 18 Вт (QC)</li>
<li><strong>Разъемы:</strong> 1 × USB Type-C, 2 × USB-A, 1 × универсальная AC-розетка</li>
<li><strong>Материал корпуса:</strong> огнестойкий пластик</li>
<li><strong>Страна производства:</strong> Китай</li>
</ul>',NULL,'retail','TATL20310001',NULL,'549.00','false','UAH',NULL,NULL,'100','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7530913640_w700_h500_universalnyj-dorozhnyj-adapter.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530913640_w700_h500_universalnyj-dorozhnyj-adapter-mZFQVmgqhNtU5nV2tuGRBDaMrinFep.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530911684_w700_h500_universalnyj-dorozhnyj-adapter-XDw0EVS9uBjjJ0rdu84lDKzLZh8Vmb.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530911843_w700_h500_universalnyj-dorozhnyj-adapter-2rL7MIP2ZbMMFJz3gFJnkhnnLBiGDZ.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530911899_w700_h500_universalnyj-dorozhnyj-adapter-e9JJU3hnmK47MPzDXZVEoviuh2SmrN.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530912007_w700_h500_universalnyj-dorozhnyj-adapter-H4JYQebRM74jYWFOYCM4N0xLsxO70K.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530912067_w700_h500_universalnyj-dorozhnyj-adapter-YAhTE44AyVCbjK3esVd51D6Sk8fwWK.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530912125_w700_h500_universalnyj-dorozhnyj-adapter-rqtFOVn7RazdjW8kFc9WpQuLvxQ9l8.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530912298_w700_h500_universalnyj-dorozhnyj-adapter-L3uMEAda9qlHcepPpFMjjit7c8aMiR.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530912451_w700_h500_universalnyj-dorozhnyj-adapter-QPsYvLoWtAEyyGdZBJAGjnVWjimzWi.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7530912539_w700_h500_universalnyj-dorozhnyj-adapter-crcMiRzfIbHaaK3YdtWr35ljHefnfl.png"]','[]','[]','true','true','false','53','0','0',NULL,NULL,NULL,NULL,'2026-07-12 15:03:43.500666+00','2026-07-12 15:03:43.500666+00',NULL,'0');
