INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('124','Кабель Baseus Explorer Series Auto Power-Off Type-C to Type-C 100W (1m)','Кабель Baseus Explorer Series Auto Power-Off Type-C to Type-C 100W (1m)','<p><strong>Baseus Explorer Series Auto Power-Off Type-C to Type-C 100W (1 м)</strong> — сучасний USB Type-C кабель із функцією <strong>автоматичного вимкнення живлення після повного заряджання пристрою</strong>. Завдяки цій технології знижується навантаження на акумулятор, запобігає перезаряджанню та продовжує термін експлуатації батареї.</p>
<p>Кабель підтримує швидке заряджання <strong>Power Delivery</strong> потужністю до <strong>100 Вт (20 В/5 А)</strong>, що робить його чудовим вибором для ноутбуків, смартфонів, планшетів, ігрових консолей та інших пристроїв із роз''ємом USB Type-C. Вбудований <strong>E-Marker</strong> автоматично визначає оптимальні параметри живлення, забезпечуючи безпечне та стабільне заряджання.</p>
<p>Високоякісні провідники з <strong>лудженої міді</strong>, міцна <strong>нейлонове обплетення</strong> і конектори з <strong>цинкового сплаву</strong> гарантують довговічність і стійкість до щоденного використання. Кабель також підтримує передавання даних зі швидкістю до <strong>480 Мбіт/с</strong>.</p>
<p>Довжина: <strong>1 метр</strong> ідеально підходить для використання вдома, в офісі, автомобілі та в поїздках.</p>
<span style="display:block;font-size:14px;margin:1em 0">Переваги:</span>
<ul>
<li>Автоматичне вимкнення після повного заряджання.</li>
<li>Підтримка Power Delivery до <strong>100 Вт</strong>.</li>
<li>Максимальний струм <strong>5 А</strong>.</li>
<li>Інтелектуальний чип <strong>E-Marker</strong>.</li>
<li>Передавання даних до <strong>480 Мбіт/с</strong>.</li>
<li>Зносостійке нейлонове обплетення.</li>
<li>Міцні конектори з цинкового сплаву.</li>
<li>Захист від перегрівання, перевантаження та перезаряджання.</li>
<li>Сумісність із ноутбуками, смартфонами, планшетами та іншими пристроями USB Type-C.</li>
</ul>
<p><strong>Комплектація</strong></p>
<ul>
<li>Кабель Baseus Explorer Series Auto Power-Off Type-C to Type-C 100W (1 м) — <strong>1 шт.</strong></li>
</ul>','<p><strong>Baseus Explorer Series Auto Power-Off Type-C to Type-C 100W (1 м)</strong> — современный USB Type-C кабель с функцией <strong>автоматического отключения питания после полной зарядки устройства</strong>. Благодаря этой технологии снижается нагрузка на аккумулятор, предотвращается перезаряд и продлевается срок службы батареи.</p>
<p>Кабель поддерживает быструю зарядку <strong>Power Delivery</strong> мощностью до <strong>100 Вт (20 В/5 А)</strong>, что делает его отличным выбором для ноутбуков, смартфонов, планшетов, игровых консолей и других устройств с разъемом USB Type-C. Встроенный <strong>E-Marker</strong> автоматически определяет оптимальные параметры питания, обеспечивая безопасную и стабильную зарядку.</p>
