INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('138','Смарт Годинник Proove Quantum (black )','Смарт Годинник Proove Quantum (black )','<p><strong>Смарт годинник Proove Quantum (Black)</strong> — стильний розумний годинник із круглим <strong>1.43" AMOLED-дисплеєм</strong>, металевим корпусом та широким набором функцій для щоденного використання. Модель підтримує синхронізацію зі смартфонами на Android та iOS, дозволяє отримувати сповіщення про дзвінки й повідомлення, а також контролювати основні показники здоров''я та фізичної активності.</p>
<p>Міцний корпус із цинкового сплаву та ABS-пластику поєднується з м''яким силіконовим ремінцем, який комфортно сидить на руці навіть під час тривалого носіння. Яскравий AMOLED-дисплей з роздільною здатністю <strong>466×466</strong> забезпечує насичені кольори та чудову читабельність. Захист <strong>IP68</strong> дозволяє не хвилюватися про пил та бризки води (не рекомендується використовувати під час плавання або прийняття душу).</p>
<p>Годинник оснащений датчиком серцевого ритму, вимірюванням рівня кисню в крові (SpO₂), моніторингом сну, крокоміром, спортивними режимами та іншими корисними функціями. Акумулятор ємністю <strong>220 мА·год</strong> забезпечує до <strong>7 днів автономної роботи</strong> без підзарядки. Підключення здійснюється через <strong>Bluetooth 5.3</strong>, а керування та перегляд статистики доступні у фірмовому мобільному застосунку.</p>
<p><strong>Переваги:</strong></p>
<ul>
<li>AMOLED-дисплей 1.43" (466×466)</li>
<li>Металевий корпус</li>
<li>Bluetooth 5.3</li>
<li>Підтримка Android та iOS</li>
<li>Моніторинг пульсу, SpO₂, сну та активності</li>
<li>Сповіщення про дзвінки та повідомлення</li>
<li>Змінний силіконовий ремінець 22 мм</li>
<li>Захист IP68</li>
<li>До 7 днів автономної роботи</li>
<li>Стильний чорний колір</li>
</ul>','<p><strong>Смарт часы Proove Quantum (Black)</strong> — стильные умные часы с круглым <strong>1.43" AMOLED-дисплеем</strong>, металлическим корпусом и широким набором функций для ежедневного использования. Модель поддерживает синхронизацию со смартфонами на Android и iOS, позволяет получать уведомления о звонках и уведомлениях, а также контролировать основные показатели здоровья и физической активности.</p>
<p>Прочный корпус из цинкового сплава и ABS-пластика сочетается с мягким силиконовым ремешком, который комфортно сидит на руке даже при длительном ношении. Яркий AMOLED-дисплей с разрешением <strong>466×466</strong> обеспечивает насыщенные цвета и отличную читаемость. Защита <strong>IP68</strong> позволяет не волноваться о пыли и брызгах воды (не рекомендуется использовать во время плавания или принятия душа).</p>
<p>Часы оснащены датчиком сердечного ритма, измерением уровня кислорода в крови (SpO2), мониторингом сна, шагомером, спортивными режимами и другими полезными функциями. Аккумулятор емкостью <strong>220 мА*ч</strong> обеспечивает до <strong>7 дней автономной работы</strong> без подзарядки. Подключение осуществляется через <strong>Bluetooth 5.3</strong>, а управление и просмотр статистики доступны в фирменном мобильном приложении.</p>
<p><strong>Преимущества:</strong></p>
<ul>
<li>AMOLED-дисплей 1.43" (466×466)</li>
<li>Металлический корпус</li>
<li>Bluetooth 5.3</li>
<li>Поддержка Android и iOS</li>
<li>Мониторинг пульса, SpO2, сна и активности</li>
<li>Оповещение о звонках и сообщениях</li>
<li>Сменный силиконовый ремешок 22 мм</li>
<li>Защита IP68</li>
<li>До 7 дней автономной работы</li>
<li>Стильный черный цвет</li>
</ul>',NULL,'retail','SWQU00000001',NULL,'1999.00','false','UAH',NULL,NULL,'100','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7544537655_w700_h500_smart-godinnik-proove.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544537655_w700_h500_smart-godinnik-proove-5I0Z8TwgGtaq2C4RG8RP814aWQkYZX.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544205985_w700_h500_smart-godinnik-proove-BWatHQQOIshUSjCv7sIjaFv4kBH1sA.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544205987_w700_h500_smart-godinnik-proove-XsRBUXZjvq0YS4Ta0ghmgE630AW8gC.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544205983_w700_h500_smart-godinnik-proove-hRoE2xY4jGz67B5ekQfHAtDkdsn4j0.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544205982_w700_h500_smart-godinnik-proove-yZaGL3MAvBoZ3XHogut72FMvRHrNUj.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544192311_w700_h500_smart-godinnik-proove-cs86i7t7sh7x4NUyAACPRwPSnT9i9V.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7544205989_w700_h500_smart-godinnik-proove-l7xUwTo32sH1pHB0N0UQa8nuHGPWZo.png"]','[]','[]','true','true','false','97','0','0',NULL,NULL,NULL,NULL,'2026-07-12 15:03:43.500666+00','2026-07-12 15:03:43.500666+00',NULL,'0');
