INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('81','Бездротові навушники Baseus Bowie H2 з активним шумозаглушенням ANC, Gray','Беспроводные наушники Baseus Bowie H2 с активным шумоподавлением ANC, Gray','<span style="display:block;font-size:16px;margin:1em 0">Бездротові навушники Baseus Bowie H2 з активним шумозаглушенням ANC, Gray</span>
<p>Baseus Bowie H2 — повнорозмірні бездротові навушники, створені для комфортного щоденного використання. Модель оснащена гібридною системою активного шумозаглушення <strong>ANC до 40 дБ</strong>, яка ефективно зменшує сторонні шуми, дозволяючи насолоджуватися музикою, фільмами або телефонними розмовами навіть у шумному середовищі.</p>
<p>40-мм динаміки з ультратонкою діафрагмою забезпечують чисте, деталізоване звучання з насиченими басами та широкою звуковою сценою. Технологія <strong>Spatial Audio</strong> створює ефект просторового звучання для більш захопливого прослуховування.</p>
<p>Навушники підтримують <strong>Bluetooth 5.2</strong>, забезпечуючи стабільне з''єднання на відстані до 10 метрів. Вбудовані 4 мікрофони з технологією ENC покращують якість голосу під час телефонних дзвінків, відфільтровуючи навколишній шум.</p>
<p>Baseus Bowie H2 працюють до <strong>33 годин</strong> без підзарядки та підтримують дротове підключення через <strong>AUX 3,5 мм</strong>, що дозволяє використовувати навушники навіть при розрядженому акумуляторі. Заряджання здійснюється через сучасний роз''єм <strong>USB Type-C</strong>.</p>
<span style="display:block;font-size:14px;margin:1em 0">Переваги:</span>
<ul>
<li>Активне шумозаглушення ANC до 40 дБ.</li>
<li>Bluetooth 5.2 зі стабільним з''єднанням.</li>
<li>Просторове звучання Spatial Audio.</li>
<li>Потужні 40-мм динаміки.</li>
<li>4 мікрофони з шумозаглушенням ENC.</li>
<li>До 33 годин автономної роботи.</li>
<li>Низька затримка для ігор та перегляду відео.</li>
<li>Підключення через Bluetooth або AUX 3,5 мм.</li>
<li>Заряджання через USB Type-C.</li>
<li>Складана конструкція та м''які амбушури для комфортного використання.</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Характеристики:</span>
<ul>
<li>Бренд: Baseus</li>
<li>Модель: Bowie H2</li>
<li>Колір: Gray (сірий)</li>
<li>Тип: накладні бездротові навушники</li>
<li>Bluetooth: 5.2</li>
<li>Динаміки: 40 мм</li>
<li>Частотний діапазон: 20 Гц – 20 кГц</li>
<li>Активне шумозаглушення: ANC</li>
<li>Мікрофони: 4 (ENC)</li>
<li>Час автономної роботи: до 33 годин</li>
<li>Час заряджання: близько 1 години</li>
<li>Інтерфейс заряджання: USB Type-C</li>
<li>Дротове підключення: AUX 3,5 мм</li>
<li>Радіус дії: до 10 м</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Комплектація:</span>
<ul>
<li>Навушники Baseus Bowie H2 Gray</li>
<li>Кабель USB Type-C</li>
<li>Аудіокабель AUX 3,5 мм</li>
<li>Інструкція користувача</li>
</ul>','<span style="display:block;font-size:16px;margin:1em 0">Беспроводные наушники Baseus Bowie H2 с активным шумоподавлением ANC, Gray</span>
<p><strong>Baseus Bowie H2</strong> — полноразмерные беспроводные наушники, созданные для комфортного ежедневного использования. Модель оснащена гибридной системой активного шумоподавления <strong>ANC до 40 дБ</strong>, которая эффективно снижает уровень внешнего шума, позволяя наслаждаться музыкой, фильмами и телефонными разговорами даже в шумной обстановке.</p>
<p>40-мм динамики с ультратонкой диафрагмой обеспечивают чистое, детализированное звучание, насыщенные басы и широкую звуковую сцену. Технология <strong>Spatial Audio</strong> создает эффект объемного звучания, делая прослушивание еще более реалистичным.</p>
<p>Наушники поддерживают <strong>Bluetooth 5.2</strong>, обеспечивая стабильное соединение на расстоянии до 10 метров. Встроенные <strong>4 микрофона с технологией ENC</strong> улучшают качество передачи голоса во время звонков, эффективно подавляя окружающие шумы.</p>
<p>Baseus Bowie H2 работают <strong>до 33 часов</strong> без подзарядки и поддерживают проводное подключение через <strong>AUX 3,5 мм</strong>, что позволяет использовать их даже при разряженном аккумуляторе. Зарядка осуществляется через современный разъем <strong>USB Type-C</strong>.</p>
<span style="display:block;font-size:14px;margin:1em 0">Преимущества:</span>
<ul>
<li>Активное шумоподавление ANC до 40 дБ.</li>
<li>Bluetooth 5.2 со стабильным соединением.</li>
<li>Пространственное звучание Spatial Audio.</li>
<li>Мощные 40-мм динамики.</li>
<li>4 микрофона с шумоподавлением ENC.</li>
<li>До 33 часов автономной работы.</li>
<li>Низкая задержка для игр и просмотра видео.</li>
<li>Подключение через Bluetooth или AUX 3,5 мм.</li>
<li>Зарядка через USB Type-C.</li>
<li>Складная конструкция и мягкие амбушюры для комфортного использования.</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Характеристики:</span>
<ul>
<li><strong>Бренд:</strong> Baseus</li>
<li><strong>Модель:</strong> Bowie H2</li>
<li><strong>Цвет:</strong> Gray (серый)</li>
<li><strong>Тип:</strong> полноразмерные беспроводные наушники</li>
<li><strong>Bluetooth:</strong> 5.2</li>
<li><strong>Динамики:</strong> 40 мм</li>
<li><strong>Частотный диапазон:</strong> 20 Гц – 20 кГц</li>
<li><strong>Активное шумоподавление:</strong> ANC</li>
<li><strong>Микрофоны:</strong> 4 (ENC)</li>
<li><strong>Время автономной работы:</strong> до 33 часов</li>
<li><strong>Время зарядки:</strong> около 1 часа</li>
<li><strong>Разъем для зарядки:</strong> USB Type-C</li>
<li><strong>Проводное подключение:</strong> AUX 3,5 мм</li>
<li><strong>Радиус действия:</strong> до 10 м</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Комплектация:</span>
<ul>
<li>Наушники Baseus Bowie H2 Gray</li>
<li>Кабель USB Type-C</li>
<li>Аудиокабель AUX 3,5 мм</li>
<li>Инструкция пользователя</li>
</ul>',NULL,'retail','NGTW260013',NULL,'3699.00','false','UAH',NULL,NULL,'98','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7545994156_w700_h500_besprovodnye-naushniki-baseus.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7545994156_w700_h500_besprovodnye-naushniki-baseus-NfM7pCA4zaYKTamnHMKPuFmoiWn23m.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7527557500_w700_h500_besprovodnye-naushniki-baseus-Od4yOZIBMYVQkGPQSF1olnFTASmBoW.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7527557733_w700_h500_besprovodnye-naushniki-baseus-eVCEHqvkQjAfOB6mWxOOBrOPFsDrKc.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7527558040_w700_h500_besprovodnye-naushniki-baseus-cdiQaKEBjEuX5bB3YIm7xVordMkdZ1.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7527558179_w700_h500_besprovodnye-naushniki-baseus-0p2hNSGO22U208LYG54jr33H7anhjj.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7527558380_w700_h500_besprovodnye-naushniki-baseus-do1n4VUVSI58YKzBvpWiAJTN80gKzY.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7527558630_w700_h500_besprovodnye-naushniki-baseus-fSwpEfiVf53J9Px5gVi7G7ejDlyeT6.png"]','[]','[]','true','true','false','40','7','1',NULL,NULL,NULL,NULL,'2026-07-12 15:03:43.500666+00','2026-07-12 19:17:50.948+00',NULL,'0');
INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('147','Мережевий зарядний пристрій WIWU Cube 67W 2C+A GaN Fast Charger Wi-G026 EU White','Сетевое зарядное устройство WIWU Cube 67W 2C+A GaN Fast Charger Wi-G026 EU White','<p><strong>WIWU Cube Wi-G026 67W GaN</strong> — потужний мережевий зарядний пристрій нового покоління, оснащений двома портами <strong>USB Type-C</strong> та одним <strong>USB-A</strong>, що дозволяє одночасно заряджати до трьох пристроїв. Завдяки технології <strong>GaN (нітрид галію)</strong> зарядний адаптер має компактні розміри, високу енергоефективність та мінімальне нагрівання навіть під час роботи на максимальній потужності.</p>
<p>Максимальна вихідна потужність <strong>67 Вт</strong> дозволяє швидко заряджати смартфони, планшети, ноутбуки, бездротові навушники, портативні консолі та інші пристрої. Зарядний пристрій підтримує сучасні протоколи швидкої зарядки <strong>Power Delivery (PD), Quick Charge (QC) та PPS</strong>, забезпечуючи оптимальну швидкість заряджання для сумісних гаджетів. Інтелектуальний чіп автоматично визначає необхідні параметри живлення та захищає пристрої від перегріву, перенапруги, перевантаження по струму та короткого замикання.</p>
<span style="display:block;font-size:14px;margin:1em 0">Переваги:</span>
<ul>
<li>Потужність до 67 Вт.</li>
<li>Технологія GaN нового покоління.</li>
<li>2 порти USB Type-C + 1 порт USB-A.</li>
<li>Одночасна зарядка до трьох пристроїв.</li>
<li>Підтримка PD, QC та PPS.</li>
<li>Компактний корпус Cube.</li>
<li>Інтелектуальний захист.</li>
<li>Підходить для смартфонів, планшетів, ноутбуків та інших USB-пристроїв.</li>
</ul>','<p><strong>WIWU Cube Wi-G026 67W GaN</strong> — мощное сетевое зарядное устройство нового поколения, оснащенное двумя портами <strong>USB Type-C</strong> и одним <strong>USB-A</strong>, что позволяет одновременно заряжать до трех устройств. Благодаря технологии <strong>GaN (нитрид галлия)</strong> зарядный адаптер имеет компактные размеры, высокую энергоэффективность и минимальный нагрев даже при работе на максимальной мощности.</p>
<p>Максимальная выходная мощность <strong>67 Вт</strong> позволяет быстро заряжать смартфоны, планшеты, ноутбуки, беспроводные наушники, портативные консоли и другие устройства. Зарядное устройство поддерживает современные протоколы быстрой зарядки <strong>Power Delivery (PD), Quick Charge (QC) та PPS</strong>обеспечивая оптимальную скорость зарядки для совместимых гаджетов. Интеллектуальный чип автоматически определяет необходимые параметры питания и защищает устройства от перегрева, перенапряжения, перегрузки по току и короткого замыкания.</p>
<span style="display:block;font-size:14px;margin:1em 0">Преимущества:</span>
<ul>
<li>Мощность до 67 Вт.</li>
<li>Технология GaN нового поколения.</li>
<li>2 порта USB Type-C + 1 порт USB-A.</li>
<li>Одновременная зарядка до трех устройств.</li>
<li>Поддержка PD, QC и PPS.</li>
<li>Компактный корпус Cube.</li>
<li>Интеллектуальная защита.</li>
<li>Подходит для смартфонов, планшетов, ноутбуков и других USB устройств.</li>
</ul>',NULL,'retail','6977703656800',NULL,'899.00','false','UAH',NULL,NULL,'100','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7560493619_w700_h500_setevoe-zaryadnoe-ustrojstvo.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7560493619_w700_h500_setevoe-zaryadnoe-ustrojstvo-2YPf8VcliOF4Fse6IWXugTz3O4Jfpz.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7560490400_w700_h500_setevoe-zaryadnoe-ustrojstvo-eZRDoKoTSOa1jSfEC4YJ4ezSebPheN.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7560490402_w700_h500_setevoe-zaryadnoe-ustrojstvo-Kkrw3h5kudujeWhYvpJrHYaXlVhoW8.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7560490405_w700_h500_setevoe-zaryadnoe-ustrojstvo-oSSvNeD7J1nJU8gRENq0FgYBlyZeXR.png"]','[]','[]','true','true','false','106','0','0',NULL,NULL,NULL,NULL,'2026-07-12 15:03:43.500666+00','2026-07-12 15:03:43.500666+00',NULL,'0');
INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('148','Бездротова ігрова миша Proove Gaming Rate Special Edition ( black/purple )','Беспроводная игровая мышь Proove Gaming Rate Special Edition ( black/purple )','<p><strong>Proove Gaming Rate Special Edition Black/Purple</strong> — сучасна бездротова ігрова миша, створена для комфортної гри та високої точності керування. Завдяки ергономічному симетричному дизайну, невеликій вазі та продуктивному оптичному сенсору вона чудово підходить як для кіберспортивних дисциплін, так і для повсякденного використання.</p>
<p>Миша оснащена високоточним сенсором із максимальною роздільною здатністю <strong>12000 DPI</strong>, що забезпечує швидке та плавне позиціонування курсора. Підтримує три режими підключення: <strong>Bluetooth</strong>, <strong>2.4 GHz</strong> через USB-ресивер та <strong>USB Type-C</strong> для дротового режиму та заряджання.</p>
<p>Вбудований акумулятор забезпечує до <strong>45 годин</strong> автономної роботи, а надійні перемикачі <strong>Kailh Black Mamba</strong> з ресурсом <strong>80 мільйонів натискань</strong> гарантують довговічність навіть при інтенсивному використанні.</p>
<p>Стильне поєднання <strong>Black/Purple (чорно-фіолетовий)</strong> гармонійно доповнить будь-який ігровий сетап, а RGB-підсвічування надає пристрою сучасного вигляду.</p>
<span style="display:block;font-size:14px;margin:1em 0">Переваги</span>
<ul>
<li>Оптичний сенсор до <strong>12000 DPI</strong></li>
<li>Три режими підключення: Bluetooth, 2.4 GHz та USB Type-C</li>
<li>Частота опитування до <strong>1000 Гц</strong></li>
<li>Легка конструкція — лише <strong>64 г</strong></li>
