INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('93','Настільна лампа з бездротовою зарядкою Proove Modern 10W Qi 15W USB Type-C LED Бежева','Настольная лампа с беспроводной зарядкой Proove Modern 10W Qi 15W USB Type-C LED Бежевая','<span style="display:block;font-size:14px;margin:1em 0">Настільна лампа з бездротовою зарядкою Proove Modern Beige</span>
<p>Стильна та функціональна <strong>Proove Modern</strong> поєднує сучасне LED-освітлення, бездротову зарядку Qi та мінімалістичний дизайн. Вона стане чудовим вибором для робочого столу, домашнього офісу, навчання або читання, а також допоможе підтримувати порядок на столі завдяки вбудованій бездротовій зарядній платформі.</p>
<p>Лампа оснащена <strong>36 світлодіодами</strong> потужністю <strong>10 Вт</strong>, які забезпечують рівномірне нейтральне освітлення з колірною температурою <strong>4000K</strong>. Сенсорне керування дозволяє швидко змінювати рівень яскравості, а <strong>3 рівні регулювання</strong> допоможуть підібрати комфортне освітлення для роботи, навчання або відпочинку.</p>
<p>Вбудована <strong>бездротова зарядка Qi</strong> підтримує потужність <strong>5 / 7.5 / 10 / 15 Вт</strong>, тому достатньо покласти сумісний смартфон на основу лампи, щоб розпочати заряджання. Для максимальної потужності 15 Вт рекомендується використовувати адаптер із підтримкою <strong>QC 2.0</strong>. Живлення лампи здійснюється через сучасний роз''єм <strong>USB Type-C</strong>.</p>
<p>Корпус виготовлений із <strong>ABS-пластику, PP та алюмінієвого сплаву</strong>, що забезпечує міцність, невелику вагу та довговічність. Елегантний <strong>бежевий</strong> колір легко поєднується як із сучасними, так і з класичними інтер''єрами.</p>
<span style="display:block;font-size:14px;margin:1em 0">Переваги:</span>
<ul>
<li>бездротова зарядка <strong>Qi до 15 Вт</strong>;</li>
<li><strong>36 LED</strong> світлодіодів;</li>
<li>потужність лампи <strong>10 Вт</strong>;</li>
<li><strong>3 рівні</strong> регулювання яскравості;</li>
<li>сенсорне керування;</li>
<li>нейтральне світло <strong>4000K</strong>;</li>
<li>живлення через <strong>USB Type-C</strong>;</li>
<li>сучасний мінімалістичний дизайн;</li>
<li>міцний корпус із пластику та алюмінію;</li>
<li>стильний бежевий колір.</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Характеристики:</span>
<ul>
<li>Тип: настільна LED-лампа</li>
<li>Потужність: <strong>10 Вт</strong></li>
<li>Кількість світлодіодів: <strong>36</strong></li>
<li>Колірна температура: <strong>4000K</strong></li>
<li>Регулювання яскравості: <strong>3 рівні</strong></li>
<li>Бездротова зарядка: <strong>Qi 5 / 7.5 / 10 / 15 Вт</strong></li>
<li>Живлення: <strong>USB Type-C (DC 5V/3A, 9V/2.1A)</strong></li>
<li>Матеріал корпусу: <strong>ABS + PP + алюмінієвий сплав</strong></li>
<li>Розміри: <strong>85 × 440 мм</strong></li>
<li>Вага: <strong>420,6 г</strong></li>
<li>Колір: <strong>Beige (бежевий)</strong>.</li>
</ul>','<span style="display:block;font-size:14px;margin:1em 0">Настольная лампа с беспроводной зарядкой Proove Modern Beige</span>
<p>Стильная и функциональная <strong>Proove Modern</strong> сочетает современное LED-освещение, беспроводную зарядку Qi и минималистичный дизайн. Она станет отличным выбором для рабочего стола, домашнего офиса, учебы или чтения, а также поможет поддерживать порядок на столе благодаря встроенной беспроводной зарядной платформе.</p>
<p>Лампа оснащена <strong>36 светодиодами</strong> мощностью <strong>10 Вт</strong>, которые обеспечивают равномерное нейтральное освещение с цветовой температурой <strong>4000K</strong>. Сенсорное управление позволяет быстро менять уровень яркости, а <strong>3 уровня регулировки</strong> помогут подобрать комфортное освещение для работы, учебы или отдыха.</p>
<p>Встроенная <strong>бездротова зарядка Qi</strong> поддерживает мощность <strong>5 / 7.5 / 10 / 15 Вт</strong>, поэтому достаточно положить совместимый смартфон на основу лампы, чтобы начать зарядку. Для максимальной мощности 15 Вт рекомендуется использовать адаптер с поддержкой <strong>QC 2.0</strong>. Питание лампы осуществляется через современный разъем <strong>USB Type-C</strong>.</p>
<p>Корпус изготовлен из <strong>ABS пластика, PP и алюминиевого сплава</strong>, что обеспечивает прочность, небольшой вес и долговечность. Элегантный <strong>бежевый</strong> цвет легко сочетается как с современными, так и с классическими интерьерами.</p>
<span style="display:block;font-size:14px;margin:1em 0">Преимущества:</span>
<ul>
<li>беспроводная зарядка <strong>Qi до 15 Вт</strong>;</li>
<li><strong>36 LED</strong> светодиодов;</li>
<li>мощность лампы <strong>10 Вт</strong>;</li>
<li><strong>3 уровня</strong> регулировка яркости;</li>
<li>сенсорное управление;</li>
<li>нейтральный свет <strong>4000K</strong>;</li>
<li>питание через <strong>USB Type-C</strong>;</li>
<li>современный минималистичный дизайн;</li>
<li>прочный корпус из пластика и алюминия;</li>
<li>стильный бежевый цвет.</li>
</ul>
<span style="display:block;font-size:14px;margin:1em 0">Характеристики:</span>
<ul>
<li>Тип: настольная LED лампа</li>
<li>Мощность: <strong>10 Вт</strong></li>
<li>Количество светодиодов: <strong>36</strong></li>
<li>Цветовая температура: <strong>4000K</strong></li>
<li>Регулировка яркости: <strong>3 уровня</strong></li>
<li>Беспроводная зарядка: <strong>Qi 5 / 7.5 / 10 / 15 Вт</strong></li>
<li>Питание: <strong>USB Type-C (DC 5V/3A, 9V/2.1A)</strong></li>
<li>Материал корпуса: <strong>ABS + PP + алюминиевый сплав</strong></li>
<li>Размеры: <strong>85 × 440 мм</strong></li>
<li>Вес: <strong>420,6 г</strong></li>
