INSERT INTO "products" ("id", "name_uk", "name_ru", "description_uk", "description_ru", "private_notes", "sales_type", "sku", "barcode", "price", "price_from", "currency", "old_price", "cost_price", "quantity", "unit", "stock_status", "site_group_id", "marketplace_category_id", "width", "height", "length", "weight", "image", "images", "sizes", "options", "is_visible", "is_in_stock", "is_popular", "sort_order", "views_count", "orders_count", "meta_title_uk", "meta_title_ru", "meta_description_uk", "meta_description_ru", "created_at", "updated_at", "deleted_at", "purchases_boost") VALUES ('41','Зарядний пристрій Essager Grace 100W GaN 4 Ports Travel Charger 2 Type-C + 2 Type-A Black','Зарядное устройство Essager 100W GaN 4 Ports Travel Charger 2 Type-C + 2 Type-A Black','ESSAGER 100W 2 Type-C 2 Type-A — передовий зарядний пристрій, розроблений для забезпечення найвищої продуктивності та універсальності в області заряджання електронних пристроїв. З двома портами USB Type-C і двома портами USB Type-A, оснащеними технологією Gallium Nitride (GaN), цей пристрій є сучасним і компактним рішенням для ефективної зарядки ваших гаджетів. Технічні характеристики: Максимальна потужність 100W: Здатність забезпечувати високу потужність дозволяє швидко заряджати різноманітні пристрої, включаючи ноутбуки, смартфони, планшети та інші гаджети. Унікальна комбінація портів забезпечує широкий діапазон сумісності з різними пристроями, що дозволяє одночасно заряджати чотири пристрої. Застосування технології GaN робить зарядний пристрій більш ефективним та компактним у порівнянні з традиційними матеріалами, забезпечуючи стабільну та швидку зарядку. Підтримка технології PD забезпечує швидке заряджання сумісних пристроїв, істотно скорочуючи час заряджання. Сумісність із різноманітними пристроями, включаючи смартфони, планшети, ноутбуки, електронні книги та інші гаджети з підтримкою USB. Вбудовані механізми захисту від перегріву, перевантаження та короткого замикання забезпечують безпеку заряджання. Сучасний зовнішній вигляд і компактні розміри роблять ESSAGER 100W 2 Type-C 2 Type-A ідеальним супутником у поїздках та повсякденному житті. ESSAGER 100W 2 Type-C 2 Type-A зарядний пристрій, який приносить у ваше життя максимальні можливості та зручність. З двома портами USB Type-C та двома портами USB Type-A, воно забезпечує не лише широкий спектр сумісності, але й найвищу ефективність завдяки використанню передової технології Gallium Nitride. Максимальна потужність 100W робить ESSAGER 100W 2 Type-C 2 Type-A ідеальним для швидкого заряджання різних пристроїв, від смартфонів до ноутбуків. Технологія Power Delivery (PD) забезпечує швидку та розумну зарядку, оптимізовану під конкретні потреби кожного пристрою. Стильний та компактний дизайн робить цей зарядний пристрій зручним для використання у будь-яких умовах. Завдяки багаторівневій системі захисту, вам не доведеться турбуватися про безпеку ваших пристроїв у процесі заряджання.','<p>ESSAGER 100W 2 Type-C 2 Type-A — передовое зарядное устройство, разработанное для обеспечения максимальной производительности и универсальности в сфере зарядки электронных устройств.</p>
<p>Оснащённое двумя портами USB Type-C и двумя портами USB Type-A с поддержкой технологии Gallium Nitride (GaN), это устройство представляет собой современное и компактное решение для эффективной зарядки ваших гаджетов.</p>
<p><strong>Технические характеристики:</strong></p>
<ul>
<li><strong>Максимальная мощность 100W:</strong> высокая выходная мощность позволяет быстро заряжать различные устройства, включая ноутбуки, смартфоны, планшеты и другие гаджеты.</li>
<li>Уникальная комбинация портов обеспечивает широкую совместимость с различными устройствами и позволяет одновременно заряжать до четырёх устройств.</li>
<li>Использование технологии GaN делает зарядное устройство более эффективным и компактным по сравнению с традиционными решениями, обеспечивая стабильную и быструю зарядку.</li>
<li>Поддержка технологии Power Delivery (PD) обеспечивает ускоренную зарядку совместимых устройств, значительно сокращая время зарядки.</li>
<li>Совместимость с различными устройствами, включая смартфоны, планшеты, ноутбуки, электронные книги и другие гаджеты с поддержкой USB.</li>
<li>Встроенные механизмы защиты от перегрева, перегрузки и короткого замыкания обеспечивают безопасную зарядку.</li>
<li>Современный дизайн и компактные размеры делают ESSAGER 100W 2 Type-C 2 Type-A идеальным спутником в поездках и повседневной жизни.</li>
</ul>
<p>ESSAGER 100W 2 Type-C 2 Type-A — это зарядное устройство, которое обеспечивает максимум возможностей и удобства.</p>
<p>Благодаря двум портам USB Type-C и двум портам USB Type-A устройство обеспечивает широкую совместимость и высокую эффективность за счёт использования передовой технологии Gallium Nitride.</p>
<p>Максимальная мощность 100W делает ESSAGER 100W 2 Type-C 2 Type-A идеальным решением для быстрой зарядки различных устройств — от смартфонов до ноутбуков.</p>
<p>Технология Power Delivery (PD) обеспечивает быструю и интеллектуальную зарядку, оптимизированную под потребности каждого устройства.</p>
<p>Стильный и компактный дизайн делает это зарядное устройство удобным для использования в любых условиях. Благодаря многоуровневой системе защиты вам не придётся беспокоиться о безопасности ваших устройств во время зарядки.</p>',NULL,'retail','ECT2CA-QYB01-Z',NULL,'949.00','false','UAH',NULL,NULL,'99','шт','В наличии',NULL,NULL,NULL,NULL,NULL,NULL,'https://images.prom.ua/7537760215_w700_h500_zaryadnoe-ustrojstvo-essager.jpg','["https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7537760215_w700_h500_zaryadnoe-ustrojstvo-essager-UBroA5auqE6Y6m6ehZbpp5Phgj0CSC.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7427094169_w700_h500_zaryadnoe-ustrojstvo-essager-hZmsu7QS3Kb6NKARYRWmKqpGIxQ69Z.png", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7416011225_w700_h500_zaryadnoe-ustrojstvo-essager-fMrwOSbypCXAJnQHN0kEHXut2O4d8w.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7415911489_w700_h500_zaryadnoe-ustrojstvo-essager-9ByGK9tbMUHG3cFCFi6hsMEvfZdPn0.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7415907197_w700_h500_zaryadnoe-ustrojstvo-essager-jqSBZ7VmrTT7MGTvl7GLskFaNPh2tQ.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7415907650_w700_h500_zaryadnoe-ustrojstvo-essager-G395ZgpTQFbQnLrzU1mFVzUM6PDQqw.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7415910670_w700_h500_zaryadnoe-ustrojstvo-essager-aE0gcEHwvz01elVBKb5cBRBZM7GQEj.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7415908014_w700_h500_zaryadnoe-ustrojstvo-essager-BQjH0GBJ2TKT2YOQg6YlFa0V7nrlip.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7415909211_w700_h500_zaryadnoe-ustrojstvo-essager-gQg4DI7hlmrmeG9M7HkuQdl7xxWUFy.jpg", "https://rm5enwhljzam6lbb.public.blob.vercel-storage.com/products/7415906613_w700_h500_zaryadnoe-ustrojstvo-essager-gCGE50C0D37HaVHoAK42ozxPBSS0Rz.jpg"]','[]','[]','true','true','true','0','1