INSERT INTO "store_settings" ("id", "store_name", "store_description", "logo_url", "favicon_url", "open_cart_after_add", "default_locale", "active_template", "social", "google_ads", "email_settings", "updated_at", "contact", "seo", "notifications", "google_auth") VALUES ('1','PowerFox','Ласкаво просимо до PowerFox! Ми спеціалізуємося на сучасних зарядних пристроях та аксесуарах для смартфонів, планшетів, ноутбуків та інших гаджетів. У нашому асортименті представлені зарядні пристрої GaN брендів: Toocki, Essager, Asometech та інших, кабелі Type-C - Type-C, автомобільні зарядні пристрої 6/8/10 ампер. Ми ретельно підбираємо товари, стежимо за актуальністю асортименту та прагнемо пропонувати оптимальне співвідношення ціни та якості. Перед відправкою перевіряємо комплектацію та стан товару, щоб ви отримали замовлення без неприємних сюрпризів. Для нас важливі чесний сервіс, швидка обробка замовлень і допомога у виборі. Якщо у вас виникли питання щодо сумісності або характеристик товару — ми завжди готові допомогти. Дякуємо, що обираєте PowerFox!',NULL,NULL,'true','uk','elegant','{"viber": {"url": "", "enabled": false}, "tiktok": {"url": "", "enabled": false}, "telegram": {"url": "", "enabled": false}, "instagram": {"url": "", "enabled": false}}','{"enabled": false, "conversionId": "", "conversionLabel": ""}','{"enabled": true, "fromName": "PowerFox", "provider": "gmail", "smtpHost": "smtp.gmail.com", "smtpPort": "465", "smtpUser": "vasadko15@gmail.com", "fromEmail": "vasadko15@gmail.com", "smtpPassword": "REDACTED_SMTP_APP_PASSWORD"}','2026-07-12 22:43:45.095+00','{"phones": [""], "widget": {"enabled": false, "channels": {"email": {"value": "", "enabled": false}, "phone": {"value": "", "enabled": false}, "viber": {"value": "", "enabled": false}, "telegram": {"value": "", "enabled": false}, "whatsapp": {"value": "", "enabled": false}}}, "address": "", "workingHours": {"fri": {"open": "09:00", "close": "18:00", "closed": false}, "mon": {"open": "09:00", "close": "18:00", "c